package com.hospital.management.controller.appointment;
import com.hospital.management.model.AvailableSlot;import com.hospital.management.service.*;import com.hospital.management.service.impl.AppointmentServiceImpl;import org.slf4j.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;import java.time.LocalDate;import java.util.List;
/** JSON endpoint for schedule-derived appointment availability. */
@WebServlet("/appointments/slots")public class AvailableSlotsServlet extends HttpServlet {private static final Logger LOGGER=LoggerFactory.getLogger(AvailableSlotsServlet.class);private final AppointmentService service;public AvailableSlotsServlet(){this(new AppointmentServiceImpl());}public AvailableSlotsServlet(AppointmentService s){service=s;}
protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{r.setCharacterEncoding("UTF-8");r.setContentType("application/json");r.setHeader("Cache-Control","no-store");String rawDoctor=q.getParameter("doctorId"),rawDate=q.getParameter("appointmentDate");Long doctor=AppointmentRequest.id(rawDoctor);LocalDate date=AppointmentRequest.date(rawDate);Long exclude=AppointmentRequest.id(q.getParameter("excludeAppointmentId"));if(doctor==null||date==null){LOGGER.info("Rejected available-slot request doctorId={} appointmentDate={}",safeNumber(rawDoctor),safeDate(rawDate));json(r,400,"{\"error\":\"Invalid doctor or appointment date\"}");return;}LOGGER.info("Available-slot request doctorId={} appointmentDate={} weekday={}",doctor,date,date.getDayOfWeek().name());try{List<AvailableSlot>x=service.getAvailableSlots(doctor,date,exclude,AppointmentRequest.user(q));if(x==null)x=List.of();LOGGER.info("Available-slot response doctorId={} appointmentDate={} returnedSlots={}",doctor,date,x.size());StringBuilder j=new StringBuilder("[");for(int i=0;i<x.size();i++){AvailableSlot s=x.get(i);if(i>0)j.append(',');j.append("{\"startTime\":\"").append(s.getStartTime()).append("\",\"endTime\":\"").append(s.getEndTime()).append("\",\"durationMinutes\":").append(s.getDurationMinutes()).append('}');}json(r,200,j.append(']').toString());}catch(RuntimeException e){LOGGER.error("Failed to load available appointment slots",e);json(r,500,"{\"error\":\"Available times could not be loaded\"}");}}
private void json(HttpServletResponse r,int status,String body)throws IOException{r.setStatus(status);r.getWriter().write(body);}private String safeNumber(String v){return v!=null&&v.matches("[0-9]{1,19}")?v:"invalid";}private String safeDate(String v){return v!=null&&v.matches("[0-9]{4}-[0-9]{2}-[0-9]{2}")?v:"invalid";}}
